diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 706cb828acc6..5d05d7cd23f0 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3721,6 +3721,7 @@ Value *InstCombinerImpl::reassociateDisjointOr(Value *LHS, Value *RHS) {
 // here. We should standardize that construct where it is needed or choose some
 // other way to ensure that commutated variants of patterns are not missed.
 Instruction *InstCombinerImpl::visitOr(BinaryOperator &I) {
+
   if (Value *V = simplifyOrInst(I.getOperand(0), I.getOperand(1),
                                 SQ.getWithInstruction(&I)))
     return replaceInstUsesWith(I, V);
@@ -4149,6 +4150,53 @@ Instruction *InstCombinerImpl::visitOr(BinaryOperator &I) {
       return BinaryOperator::CreateOr(Ov, NewCmp);
     }
   }
+  // Handle multiplication overflow pattern.
+  const WithOverflowInst *WOMul;
+  const Value *WOVMul;
+  const APInt *C1Mul, *C2Mul;
+  Value *OvMul;
+  CmpPredicate PredMul;
+  if (match(&I, m_c_Or(m_CombineAnd(m_ExtractValue<1>(m_CombineAnd(
+                                        m_WithOverflowInst(WOMul), m_Value(WOVMul))),
+                                    m_Value(OvMul)),
+                       m_OneUse(m_ICmp(PredMul, m_ExtractValue<0>(m_Deferred(WOVMul)),
+                                       m_APInt(C2Mul))))) &&
+      WOMul->getBinaryOp() == Instruction::Mul &&
+      (ICmpInst::isEquality(PredMul) ||
+       WOMul->isSigned() == ICmpInst::isSigned(PredMul))) {
+    // matched multiplication overflow pattern
+    // Determine constant multiplier C1 and variable operand X.
+    const APInt *C1MulTmp;
+    Value *X;
+    if (match(WOMul->getRHS(), m_APInt(C1MulTmp))) {
+      C1Mul = C1MulTmp;
+      X = WOMul->getLHS();
+    } else if (match(WOMul->getLHS(), m_APInt(C1MulTmp))) {
+      C1Mul = C1MulTmp;
+      X = WOMul->getRHS();
+    } else {
+      return nullptr;
+    }
+    // C1 must not be zero (division by zero).
+    if (C1Mul->isZero())
+      return nullptr;
+    bool IsSigned = WOMul->isSigned();
+    unsigned BitWidth = C2Mul->getBitWidth();
+    // For unsigned multiplication with UGT predicate.
+    if (!IsSigned && PredMul == ICmpInst::ICMP_UGT) {
+      APInt NewC = C2Mul->udiv(*C1Mul);
+      // Overflow threshold: floor((2^N - 1) / C1)
+      APInt Max = APInt::getMaxValue(BitWidth);
+      APInt OverflowThreshold = Max.udiv(*C1Mul);
+      // Overflow flag is true when X > OverflowThreshold.
+      // Since OverflowThreshold >= NewC (because Max >= *C2Mul),
+      // overflow flag implies X > NewC. Therefore overflow flag is redundant.
+      // Replace the whole OR with X > NewC.
+      CmpInst *NewCmp = ICmpInst::Create(Instruction::ICmp, ICmpInst::ICMP_UGT, X,
+                                          ConstantInt::get(X->getType(), NewC));
+      return NewCmp;
+    }
+  }

   // (~x) | y  -->  ~(x & (~y))  iff that gets rid of inversions
   if (sinkNotIntoOtherHandOfLogicalOp(I))

